#[derive(Debug, Clone, Default)]
pub struct UserInclude {
    pub posts: bool,
}
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct UserWithRelations {
    #[serde(flatten)]
    pub data: User,
    pub posts: Option<Vec<super::post::Post>>,
}
impl User {
    /// Load relations for a batch of records.
    pub(crate) async fn load_relations(
        records: Vec<User>,
        include: &UserInclude,
        client: &DatabaseClient,
    ) -> Result<Vec<UserWithRelations>, FerriormError> {
        let mut posts_map: std::collections::HashMap<String, Vec<super::post::Post>> = std::collections::HashMap::new();
        if include.posts {
            let ids: Vec<String> = records.iter().map(|r| r.id.clone()).collect();
            if !ids.is_empty() {
                macro_rules! build_in_query {
                    ($db:ty) => {
                        { let mut qb = sqlx::QueryBuilder:: < $db >
                        ::new("SELECT * FROM \"posts\" WHERE \"author_id\" IN ("); let
                        mut sep = qb.separated(", "); for id in & ids { sep.push_bind(id
                        .clone()); } qb.push(")"); qb }
                    };
                }
                macro_rules! insert_rows {
                    ($rows:expr) => {
                        for row in $rows { posts_map.entry(row.author_id.clone())
                        .or_default().push(row); }
                    };
                }
                match client {
                    DatabaseClient::Postgres(pool) => {
                        let mut qb = build_in_query!(sqlx::Postgres);
                        let related_rows: Vec<super::post::Post> = qb
                            .build_query_as()
                            .fetch_all(pool)
                            .await
                            .map_err(FerriormError::from)?;
                        insert_rows!(related_rows);
                    }
                    DatabaseClient::Sqlite(pool) => {
                        let mut qb = build_in_query!(sqlx::Sqlite);
                        let related_rows: Vec<super::post::Post> = qb
                            .build_query_as()
                            .fetch_all(pool)
                            .await
                            .map_err(FerriormError::from)?;
                        insert_rows!(related_rows);
                    }
                }
            }
        }
        let mut results = Vec::with_capacity(records.len());
        for r in records {
            results
                .push(UserWithRelations {
                    posts: if include.posts {
                        Some(posts_map.remove(&r.id).unwrap_or_default())
                    } else {
                        None
                    },
                    data: r,
                });
        }
        Ok(results)
    }
}
impl<'a> FindManyQuery<'a> {
    pub fn include(self, include: UserInclude) -> FindManyWithIncludeQuery<'a> {
        FindManyWithIncludeQuery {
            inner: self,
            include,
        }
    }
}
pub struct FindManyWithIncludeQuery<'a> {
    inner: FindManyQuery<'a>,
    include: UserInclude,
}
impl<'a> FindManyWithIncludeQuery<'a> {
    pub async fn exec(self) -> Result<Vec<UserWithRelations>, FerriormError> {
        let include = self.include;
        let client = self.inner.client;
        let records = FindManyQuery {
            client,
            r#where: self.inner.r#where,
            order_by: self.inner.order_by,
            skip: self.inner.skip,
            take: self.inner.take,
        }
            .exec()
            .await?;
        User::load_relations(records, &include, client).await
    }
}
impl<'a> FindUniqueQuery<'a> {
    pub fn include(self, include: UserInclude) -> FindUniqueWithIncludeQuery<'a> {
        FindUniqueWithIncludeQuery {
            inner: self,
            include,
        }
    }
}
pub struct FindUniqueWithIncludeQuery<'a> {
    inner: FindUniqueQuery<'a>,
    include: UserInclude,
}
impl<'a> FindUniqueWithIncludeQuery<'a> {
    pub async fn exec(self) -> Result<Option<UserWithRelations>, FerriormError> {
        let include = self.include;
        let client = self.inner.client;
        let record = FindUniqueQuery {
            client,
            r#where: self.inner.r#where,
        }
            .exec()
            .await?;
        match record {
            Some(r) => {
                let mut results = User::load_relations(vec![r], &include, client).await?;
                Ok(results.pop())
            }
            None => Ok(None),
        }
    }
}
